const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const FIRST_INSURANCE_RATE = 0.1;
const PROCESSING_FEE = 5;

export function processScenario(input: any): any {
  const results = input.steps.map((step: any) => {
    let policyBase = 0;
    const componentCounts: Record<string, number> = {};
    for (const item of step.items) {
      if (COMPONENT_TYPES.has(item.type)) {
        componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
      } else {
        policyBase += BASE_PREMIUMS[item.type];
      }
    }
    for (const type in componentCounts) {
      const count = componentCounts[type];
      if (count === BLOCK_SIZE) {
        policyBase += BLOCK_PREMIUM;
      } else {
        policyBase += count * BASE_PREMIUMS[type];
      }
    }
    const premium = Math.ceil(policyBase + policyBase * FIRST_INSURANCE_RATE + PROCESSING_FEE);
    return { premium };
  });
  return { results };
}

