describe("Claim", () => {
  it("should deduct 100G deductible from damage on a regular item", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: false },
          ],
        },
        {
          op: "claim" as const,
          policy: 0,
          incident: {
            cause: "dragon attack",
            damages: [{ itemType: "sword", amount: 500 }],
          },
        },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 400, remainingCap: 1600 });
  });
  it.todo("should reimburse at 50% for items with enchantment >= 8 then deductible");
  it.todo("should fully reimburse dragon material items then deductible");
  it.todo("should apply deductible per damaged item in multi-damage events");
  it.todo("should cap total payout at 2x insurance sum across claims");
});

